// === Diff: which chunk IDs are new, which are stale ===
const newChunks = $('Chunk + Hash').all().map(it => it.json);
const scroll = $input.first().json;

const existingPoints = (scroll && scroll.result && scroll.result.points) || [];
const existingIds = new Set(existingPoints.map(p => String(p.id)));
const newIdSet = new Set(newChunks.map(c => c.pointId));

const toInsert = newChunks.filter(c => !existingIds.has(c.pointId));
const toDeleteIds = existingPoints
  .filter(p => !newIdSet.has(String(p.id)))
  .map(p => p.id);

return [{
  json: {
    summary: {
      totalChunks: newChunks.length,
      newChunks: toInsert.length,
      removedChunks: toDeleteIds.length,
      unchangedChunks: newChunks.length - toInsert.length
    },
    toInsert,
    toDeleteIds,
    versionId: newChunks[0] ? newChunks[0].versionId : null,
    documentUrl: newChunks[0] ? newChunks[0].documentUrl : null,
    documentHash: newChunks[0] ? newChunks[0].documentHash : null
  }
}];

// Combine the chunk metadata with the embedding into one Qdrant point.
const chunk = $('Split: New Chunks').item.json;
const embed = $input.item.json;

return {
  json: {
    point: {
      id: chunk.pointId,
      vector: embed.embedding,
      payload: {
        content: chunk.chunkText,
        metadata: {
          chunkHash: chunk.chunkHash,
          chunkIndex: chunk.chunkIndex,
          documentUrl: chunk.documentUrl,
          documentHash: chunk.documentHash,
          versionId: chunk.versionId
        }
      }
    }
  }
};

// === Manual SigV4 signing for Bedrock (works around n8n issue #14623) ===
const crypto = require('crypto');
const https = require('https');

// --- Inputs ---
const cfg = $('Set Config').first().json;
const region = cfg.awsRegion;
const modelId = cfg.embedModelId;
const dimensions = cfg.embedDimensions;
const accessKeyId = cfg.awsAccessKeyId;
const secretAccessKey = cfg.awsSecretAccessKey;
const sessionToken = cfg.awsSessionToken || null;
const chunkText = $json.chunkText;

if (!accessKeyId || !secretAccessKey) {
  throw new Error('awsAccessKeyId / awsSecretAccessKey missing from Set Config node');
}
if (!chunkText) {
  throw new Error('No chunkText on input item -- check upstream node mode and connections');
}

// --- SigV4 signing ---
const service = 'bedrock';                                  // the n8n bug fix
const host = `bedrock-runtime.${region}.amazonaws.com`;

// Path for the actual request: URI-encoded ONCE
const requestPath = `/model/${encodeURIComponent(modelId)}/invoke`;
// Path for SigV4 canonical URI: URI-encoded TWICE (required for all services except S3)
const canonicalUri = `/model/${encodeURIComponent(encodeURIComponent(modelId))}/invoke`;

const body = JSON.stringify({ inputText: chunkText, dimensions, normalize: true });
const amzDate = new Date().toISOString().replace(/[:-]|\.\d{3}/g, '');
const dateStamp = amzDate.slice(0, 8);
const payloadHash = crypto.createHash('sha256').update(body).digest('hex');

const headersToSign = {
  'content-type': 'application/json',
  'host': host,
  'x-amz-content-sha256': payloadHash,
  'x-amz-date': amzDate,
};
if (sessionToken) headersToSign['x-amz-security-token'] = sessionToken;

const sortedKeys = Object.keys(headersToSign).sort();
const canonicalHeaders = sortedKeys.map(k => `${k}:${headersToSign[k]}\n`).join('');
const signedHeaders = sortedKeys.join(';');

const canonicalRequest = ['POST', canonicalUri, '', canonicalHeaders, signedHeaders, payloadHash].join('\n');
const credentialScope = `${dateStamp}/${region}/${service}/aws4_request`;
const stringToSign = [
  'AWS4-HMAC-SHA256',
  amzDate,
  credentialScope,
  crypto.createHash('sha256').update(canonicalRequest).digest('hex'),
].join('\n');

const kDate = crypto.createHmac('sha256', 'AWS4' + secretAccessKey).update(dateStamp).digest();
const kRegion = crypto.createHmac('sha256', kDate).update(region).digest();
const kService = crypto.createHmac('sha256', kRegion).update(service).digest();
const kSigning = crypto.createHmac('sha256', kService).update('aws4_request').digest();
const signature = crypto.createHmac('sha256', kSigning).update(stringToSign).digest('hex');

const authorization =
  `AWS4-HMAC-SHA256 Credential=${accessKeyId}/${credentialScope}, ` +
  `SignedHeaders=${signedHeaders}, Signature=${signature}`;

// --- Send request: promise ALWAYS resolves, errors are returned as data ---
const httpResult = await new Promise((resolve) => {
  const req = https.request(
    {
      hostname: host,
      path: requestPath,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Amz-Date': amzDate,
        'X-Amz-Content-Sha256': payloadHash,
        Authorization: authorization,
        ...(sessionToken ? { 'X-Amz-Security-Token': sessionToken } : {}),
      },
    },
    (res) => {
      const chunks = [];
      res.on('data', (c) => chunks.push(c));
      res.on('end', () => {
        resolve({
          ok: true,
          status: res.statusCode,
          body: Buffer.concat(chunks).toString('utf8'),
        });
      });
    }
  );
  req.on('error', (e) => resolve({ ok: false, error: e && e.message ? e.message : String(e) }));
  req.write(body);
  req.end();
});

// --- Top-level error handling: throw fresh Error objects only ---
if (!httpResult.ok) {
  throw new Error('Bedrock network error: ' + httpResult.error);
}
if (httpResult.status < 200 || httpResult.status >= 300) {
  throw new Error('Bedrock HTTP ' + httpResult.status + ': ' + httpResult.body.slice(0, 800));
}

let parsed;
try {
  parsed = JSON.parse(httpResult.body);
} catch (_) {
  throw new Error('Bedrock returned non-JSON: ' + httpResult.body.slice(0, 800));
}

if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
  throw new Error('Bedrock response was not a JSON object: ' + JSON.stringify(parsed).slice(0, 500));
}
if (!Array.isArray(parsed.embedding)) {
  throw new Error('Bedrock response missing embedding array: ' + JSON.stringify(parsed).slice(0, 500));
}

return { json: parsed };

// === Capture the diff as a run record before any inserts/deletes happen ===
const crypto = require('crypto');
const https = require('https');

// --- Inputs ---
const cfg = $('Set Config').first().json;
const diff = $json;

const qdrantApiKey = cfg.qdrantApiKey || '';
const chunksColl = cfg.qdrantCollection;
const runsColl = cfg.qdrantRunsCollection || 'regulatory_docs_runs';

// Parse Qdrant URL manually (URL global is not exposed in n8n's Code sandbox)
const m = String(cfg.qdrantUrl).match(/^(https?):\/\/([^:/]+)(?::(\d+))?/);
if (!m) throw new Error('Invalid qdrantUrl in Set Config: ' + cfg.qdrantUrl);
const qProtocol = m[1];
const qHostname = m[2];
const qPort = m[3] ? parseInt(m[3], 10) : (qProtocol === 'https' ? 443 : 80);
const transport = qProtocol === 'https' ? https : require('http');

// --- Promise-resolving Qdrant call (same pattern as the Bedrock node) ---
function qdrantCall(method, path, body) {
  const payload = body ? JSON.stringify(body) : '';
  return new Promise((resolve) => {
    const req = transport.request(
      {
        hostname: qHostname,
        port: qPort,
        path,
        method,
        headers: {
          'Content-Type': 'application/json',
          'api-key': qdrantApiKey,
          'Content-Length': Buffer.byteLength(payload),
        },
      },
      (res) => {
        const chunks = [];
        res.on('data', (c) => chunks.push(c));
        res.on('end', () => {
          resolve({ status: res.statusCode, body: Buffer.concat(chunks).toString('utf8') });
        });
      },
    );
    req.on('error', (e) => resolve({ status: 0, body: 'NETWORK: ' + e.message }));
    if (payload) req.write(payload);
    req.end();
  });
}

function deterministicUuid(input) {
  const h = crypto.createHash('sha1').update(input).digest();
  h[6] = (h[6] & 0x0f) | 0x50;
  h[8] = (h[8] & 0x3f) | 0x80;
  const hex = h.toString('hex');
  return [hex.slice(0, 8), hex.slice(8, 12), hex.slice(12, 16), hex.slice(16, 20), hex.slice(20, 32)].join('-');
}

// --- 1. Fetch text of chunks that are about to be deleted ---
let removed = [];
if (Array.isArray(diff.toDeleteIds) && diff.toDeleteIds.length > 0) {
  const r = await qdrantCall('POST', `/collections/${chunksColl}/points`, {
    ids: diff.toDeleteIds,
    with_payload: true,
    with_vector: false,
  });
  if (r.status < 200 || r.status >= 300) {
    throw new Error('Qdrant fetch-stale failed ' + r.status + ': ' + r.body.slice(0, 400));
  }
  const parsed = JSON.parse(r.body);
  removed = (parsed.result || []).map((p) => ({
    pointId: p.id,
    chunkIndex: p.payload && p.payload.metadata && p.payload.metadata.chunkIndex,
    chunkHash: p.payload && p.payload.metadata && p.payload.metadata.chunkHash,
    previousVersionId: p.payload && p.payload.metadata && p.payload.metadata.versionId,
    chunkText: p.payload && p.payload.content,
  }));
}

// --- 2. Build the run record (deterministic Qdrant point id for upserts) ---
const runPointId = deterministicUuid(`run::${diff.documentUrl}::${diff.versionId}`);

const runRecord = {
  runId: diff.versionId + '_' + crypto.randomBytes(3).toString('hex'),
  timestamp: diff.versionId,
  versionId: diff.versionId,
  documentUrl: diff.documentUrl,
  documentHash: diff.documentHash,
  fullText: $('Chunk + Hash').first().json.fullText,
  summary: diff.summary,
  added: (diff.toInsert || []).map((c) => ({
    pointId: c.pointId,
    chunkIndex: c.chunkIndex,
    chunkHash: c.chunkHash,
    chunkText: c.chunkText,
  })),
  removed,
};

// --- 3. Write the run record to the runs collection ---
const w = await qdrantCall('PUT', `/collections/${runsColl}/points?wait=true`, {
  points: [{ id: runPointId, vector: [0.0], payload: runRecord }],
});
if (w.status < 200 || w.status >= 300) {
  throw new Error('Qdrant write-run failed ' + w.status + ': ' + w.body.slice(0, 400));
}

// --- 4. Pass through the original diff so downstream branches keep working ---
return { json: { ...diff, runRecord, runPointId } };

// === Merge SummaryAgent JSON into run payload and upsert same Qdrant point ===
const crypto = require('crypto');
const https = require('https');

const cfg = $('Set Config').first().json;
const base = $('Build & Write Run Record').first().json;
const llm = $input.first().json;

const qdrantApiKey = cfg.qdrantApiKey || '';
const runsColl = cfg.qdrantRunsCollection || 'regulatory_docs_runs';

const m = String(cfg.qdrantUrl).match(/^(https?):\/\/([^:/]+)(?::(\d+))?/);
if (!m) throw new Error('Invalid qdrantUrl in Set Config: ' + cfg.qdrantUrl);
const qProtocol = m[1];
const qHostname = m[2];
const qPort = m[3] ? parseInt(m[3], 10) : (qProtocol === 'https' ? 443 : 80);
const transport = qProtocol === 'https' ? https : require('http');

function qdrantCall(method, path, body) {
  const payload = body ? JSON.stringify(body) : '';
  return new Promise((resolve) => {
    const req = transport.request(
      {
        hostname: qHostname,
        port: qPort,
        path,
        method,
        headers: {
          'Content-Type': 'application/json',
          'api-key': qdrantApiKey,
          'Content-Length': Buffer.byteLength(payload),
        },
      },
      (res) => {
        const chunks = [];
        res.on('data', (c) => chunks.push(c));
        res.on('end', () => {
          resolve({ status: res.statusCode, body: Buffer.concat(chunks).toString('utf8') });
        });
      },
    );
    req.on('error', (e) => resolve({ status: 0, body: 'NETWORK: ' + e.message }));
    if (payload) req.write(payload);
    req.end();
  });
}

const runRecord = { ...base.runRecord };
runRecord.llmSummary = llm.llm_summary || llm.llmSummary || '';
runRecord.materialityNotes = llm.materiality_notes || llm.materialityNotes || '';
runRecord.agentsModelId = llm.model_id || llm.modelId || '';

const w = await qdrantCall('PUT', `/collections/${runsColl}/points?wait=true`, {
  points: [{ id: base.runPointId, vector: [0.0], payload: runRecord }],
});
if (w.status < 200 || w.status >= 300) {
  throw new Error('Qdrant merge-llm failed ' + w.status + ': ' + w.body.slice(0, 400));
}

return { json: { ...base, runRecord } };

